const body = $json.body ?? $json;
const propertyId = String(body.propertyId ?? '').trim();
const template = String(body.template ?? 'standard-om-v1').trim() || 'standard-om-v1';
const mode = String(body.mode ?? 'draft').trim() || 'draft';
if (!propertyId) {
  throw new Error('propertyId is required');
}
const runId = `run_${Date.now()}`;
const safe = (value, fallback = 'unknown') => String(value || '').trim().toLowerCase().replace(/[^a-z0-9._-]+/g, '-').replace(/-+/g, '-').replace(/^[-._]+|[-._]+$/g, '') || fallback;
const propertyKey = safe(propertyId, 'property');
const htmlVersion = 'v1';
const pdfVersion = 'v1';
return [{
  json: {
    propertyId,
    template,
    mode,
    runId,
    storage: {
      propertyRoot: `properties/${propertyKey}`,
      publicRoot: `properties/${propertyKey}/public`,
      privateRoot: `properties/${propertyKey}/private`,
      omInputSnapshotPath: `properties/${propertyKey}/private/generated/om-input/${safe(runId, 'run')}.json`,
      narrativeSnapshotPath: `properties/${propertyKey}/private/generated/narrative/${safe(runId, 'run')}.json`,
      htmlDraftPath: `properties/${propertyKey}/private/generated/html/${safe(runId, 'run')}/${safe(htmlVersion, 'v1')}.html`,
      pdfDraftPath: `properties/${propertyKey}/private/generated/om-drafts/${safe(runId, 'run')}/${safe(pdfVersion, 'v1')}.pdf`
    }
  }
}];

const data = $json;
const sections = data.sections || {};
const required = ['executiveSummary','propertyDescription','locationOverview','demographicsSummary','highlights','disclaimer'];
for (const key of required) {
  if (!(key in sections)) throw new Error(`Missing drafted section: ${key}`);
}
if (!Array.isArray(sections.highlights)) throw new Error('sections.highlights must be an array');
if (!Array.isArray(data.warnings)) throw new Error('warnings must be an array');
if (!Array.isArray(data.missingInputs)) throw new Error('missingInputs must be an array');
if (!data.metadata || typeof data.metadata.template !== 'string') throw new Error('metadata.template is required');
if (typeof data.metadata.draftVersion !== 'number') throw new Error('metadata.draftVersion is required');
return [{ json: data }];

const error = $json.error || $json.message || 'Workflow failed';
const propertyId = $('Init Request + Paths').item.json.propertyId;
const runId = $('Init Request + Paths').item.json.runId;
return [{ json: { propertyId, runId, error: String(error) } }];
